// Based on "Location â€“ Detail" output
const row = items[0].json;

// ---------- Terminals list ----------

let terminals = [];
if (Array.isArray(row.terminals_list)) {
  terminals = row.terminals_list;
} else if (typeof row.terminals_list === 'string') {
  try {
    terminals = JSON.parse(row.terminals_list);
  } catch (e) {
    terminals = [];
  }
} else if (row.terminals_list && typeof row.terminals_list === 'object') {
  terminals = row.terminals_list;
}

// Normalize & sort
terminals = (terminals || [])
  .map(t => String(t).trim())
  .filter(t => t.length > 0);

terminals.sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));

const total = Number(row.terminals_total ?? terminals.length) || 0;

// ---------- Shared header lines ----------

const headerLines = [];

headerLines.push(`# ${row.name}`);
headerLines.push('');

headerLines.push(`- **Location Type:** ${row.location_type || 'Unknown'}`);
headerLines.push(`- **System:** ${row.system_name || 'Unknown'}`);
headerLines.push(`- **Body / Orbit:** ${row.body_name_or_orbit || 'N/A'}`);
headerLines.push(`- **UEX Location ID:** ${row.uex_location_id || 'N/A'}`);
headerLines.push('');

// Overview stub (you can wire proper description later)
// headerLines.push('## Overview');
// headerLines.push('');
// headerLines.push('_TODO: Add description, landmarks, and gameplay notes for this location._');
// headerLines.push('');

// ---------- SUMMARY VERSION (limited list) ----------

let suffixSummary = '';
let shownSummary = terminals;
if (total > 5) {
  shownSummary = terminals.slice(0, 5);
  suffixSummary = ` (${shownSummary.length} of ${total})`;
}

const summaryLines = [...headerLines];

summaryLines.push(`## Trade Terminals${suffixSummary}`);
summaryLines.push('');
summaryLines.push('> _Note: Lists below are unordered and not ranked._');
summaryLines.push('');

if (shownSummary.length === 0) {
  summaryLines.push('_No trade terminals with live commodity prices are currently tracked at this location._');
} else {
  for (const name of shownSummary) {
    summaryLines.push(`- ${name}`);
  }
  if (total > shownSummary.length) {
    summaryLines.push('â€¦ and more');
  }
}

// ---------- DETAILED VERSION (full list) ----------

const detailedLines = [...headerLines];

detailedLines.push('## Trade Terminals');
detailedLines.push('');
detailedLines.push('> _Detailed view. Lists below are unordered and not ranked._');
detailedLines.push('');

if (terminals.length === 0) {
  detailedLines.push('_No trade terminals with live commodity prices are currently tracked at this location._');
} else {
  for (const name of terminals) {
    detailedLines.push(`- ${name}`);
  }
}

// ---------- Slug + file paths ----------

const slug = row.slug ||
  row.name.toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');

const filePathSummary  = `/RAG/KB/locations/${slug}.md`;
const filePathDetailed = `/RAG/KB/locations/${slug}_detailed.md`;

return [
  {
    json: {
      location_id: row.id,
      slug,
      name: row.name,

      markdown_summary: summaryLines.join('\n'),
      filePath_summary: filePathSummary,

      markdown_detailed: detailedLines.join('\n'),
      filePath_detailed: filePathDetailed,
    },
  },
];

